1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const BLOCK_SIZE = 3;
4	const BLOCK_PREMIUM = 60;
5	
6	const BASE_PREMIUMS: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	  rune: 25,
12	};
13	
14	type Item = { type: string };
15	
16	const isBlockOfThreeAlike = (items: Item[]): boolean =>
17	  items.length === BLOCK_SIZE && items.every((item) => item.type === items[0].type);
18	
19	const sumOfBasePremiums = (items: Item[]): number =>
20	  items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
21	
22	const basePremiumFor = (items: Item[]): number =>
23	  isBlockOfThreeAlike(items) ? BLOCK_PREMIUM : sumOfBasePremiums(items);
24	
25	const quotePremium = (base: number): number =>
26	  Math.ceil(base + base * FIRST_INSURANCE_RATE + PROCESSING_FEE);
27	
28	export const runScenario = (scenario: any): unknown => {
29	  const base = basePremiumFor(scenario.steps[0].items);
30	  return { results: [{ premium: quotePremium(base) }] };
31	};
